import{_ as e,o as l,c as t,a5 as r}from"./chunks/framework.B5tqjWbr.js";const P=JSON.parse('{"title":"教程 0038：三相 SRF-PLL 锁相","description":"","frontmatter":{"title":"教程 0038：三相 SRF-PLL 锁相","date":"2026-07-02T00:00:00.000Z","section":"电源控制","chapter":"01-Lessons","chapterTitle":"电源课程","category":"电源控制","tags":["imported"],"source":"power","sourcePath":"0038-three-phase-srf-pll.html","status":"learning","visibility":"public","summary":"Imported from 0038-three-phase-srf-pll.html","chapterOrder":10},"headers":[],"relativePath":"content/power/lessons/0038-three-phase-srf-pll.md","filePath":"content/power/lessons/0038-three-phase-srf-pll.md","lastUpdated":null}'),i={name:"content/power/lessons/0038-three-phase-srf-pll.md"};function o(h,a,s,n,p,d){return l(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="教程-0038-三相-srf-pll-锁相" tabindex="-1">教程 0038：三相 SRF-PLL 锁相 <a class="header-anchor" href="#教程-0038-三相-srf-pll-锁相" aria-label="Permalink to &quot;教程 0038：三相 SRF-PLL 锁相&quot;">​</a></h1><p>中文主讲。一个概念：三相并网设备用同步旋转坐标系锁相环把 dq 坐标的角度对准电网。</p><p>目录</p><ul><li>它是什么</li><li>为什么 UPS 需要它</li><li>物理直觉</li><li>数学形式</li><li>一个仿真任务与仿真观察</li><li>固件落地</li><li>常见误解</li><li>验收标准、复盘问题、导师问题</li></ul><p>**保密边界：**只讨论公开 SRF-PLL 结构，不记录公司锁相参数、滤波器系数或异常电网策略。</p><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>同步旋转坐标系锁相环（synchronous reference frame PLL / SRF-PLL）先对三相电网电压做 Clarke/Park 变换，再把 q 轴电压调到 0。q 轴为 0 时，估算角度 theta 与电网电压矢量对齐。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>三相 Vienna PFC、并网 PCS 和旁路同步都需要知道电网相位。没有可靠 PLL，dq 电流环的 d/q 含义会漂移，P/Q 控制也会把有功和无功混在一起。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>把 theta 想成一只旋转的手电筒。如果它正好照向电网电压矢量，侧向阴影 q 轴为 0；如果它偏左或偏右，q 轴误差会告诉 PI 控制器该加速还是减速。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>vq = -v_alpha * sin(theta) + v_beta * cos(theta) omega = omega_nominal + PI(0 - vq) theta = theta + omega * Ts</p><p>三相 SRF-PLL 比单相 SOGI/SRF-PLL 少一个构造正交信号的步骤，因为三相本身能经 Clarke 变换得到 alpha/beta。</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>给三相电压加入 10 度初始相位误差，观察 <code>vq</code> 收敛到 0、<code>theta_err</code> 收敛到锁定带内。再加入电压跌落，观察 PLL 带宽和噪声的折中。</p><p>产物</p><ul><li>一张 vq、频率估算和相位误差曲线。</li><li>一句导师问题：锁相带宽优先抗扰动还是抗噪声？</li></ul><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>控制 ISR 中常见顺序是采样 <code>vabc</code>，执行 Clarke/Park，运行 PLL PI，限幅频率，积分 theta，再把 theta 提供给 PFC 或 PCS 电流环。</p><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li>**误解：**三相 PLL 不需要滤波。 **纠正：**不平衡、谐波和采样噪声仍会进入 vq。</li><li>**误解：**PLL 越快越好。 **纠正：**带宽越高，噪声越容易进 theta。</li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li>能说明 SRF-PLL 为什么控制 vq 到 0。</li><li>能画出 vabc -&gt; Clarke -&gt; Park -&gt; PI -&gt; theta 的链路。</li><li>能区分单相 PLL 和三相 PLL 的正交信号来源。</li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li>如果 theta 滞后电网，vq 的符号会怎样影响 omega？</li><li>电压跌落时，PLL 是否应该立即判失锁？</li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li>真实三相 UPS/PCS 中，PLL 失锁通常如何传递给模式状态机？</li><li>我只记录通用锁相结构，不记录内部带宽和阈值。</li></ul><p>**下一步：**用 PLL 角度进入 dq 电流环解耦。</p><p>源稿：<code>concepts/control/three-phase-srf-pll.md</code></p><p>上一节：教程 0037：三相功率与 dq 坐标变换下一节：教程 0039：三相 dq 电流环解耦</p>',31)])])}const u=e(i,[["render",o]]);export{P as __pageData,u as default};
